// The "Prompt Machine" Core Logic
async function promptMachine(humanInput) {
  // 1. Extract Intent
  const intent = await extractIntent(humanInput);

  // 2. Generate Optimized System Prompt
  const machinePrompt = `You are a CRM/Calendar Specialist.
    Target: ${intent.homeowner}.
    Task: ${intent.action}.
    Constraint: Do not deviate from the CRM schema.`;

  // 3. Send to Model & Return "Human" Result
  const response = await callModel(machinePrompt);
  return translateToHuman(response);
}
